def generate_sequence(n):
  seq = [0]
  seen_pairs = set()
  for _ in range(n):
    current = seq[-1]
    d = 0
    while True:
      if current - d >= 0 and (current, current - d) not in seen_pairs:
        next_term = current - d
        break
      if current + d >= 0 and (current, current + d) not in seen_pairs:
        next_term = current + d
        break
      d += 1
    seen_pairs.add((current, next_term))
    seq.append(next_term)
  return seq
